class SecurityManager {
    static let shared = SecurityManager()
    
    private init() {}
    
    func performSecurityChecks() -> Bool {
        return !isJailbroken() && !isDebugged() && !isReverseEngineered()
    }
    
    private func isJailbroken() -> Bool {
        #if targetEnvironment(simulator)
        return false
        #else
        let jailbreakPaths = [
            "/Applications/Cydia.app",
            "/Library/MobileSubstrate/MobileSubstrate.dylib",
            "/bin/bash",
            "/usr/sbin/sshd",
            "/etc/apt",
            "/private/var/lib/apt/",
            "/private/var/lib/cydia",
            "/private/var/stash"
        ]
        
        for path in jailbreakPaths {
            if FileManager.default.fileExists(atPath: path) {
                return true
            }
        }
        
        if canOpenCydia() {
            return true
        }
        
        if canWriteToPrivateDirectory() {
            return true
        }
        
        if hasSuspiciousLibraries() {
            return true
        }
        
        return false
        #endif
    }
    
    private func canOpenCydia() -> Bool {
        if let url = URL(string: "cydia://package/com.example.package") {
            return UIApplication.shared.canOpenURL(url)
        }
        return false
    }
    
    private func canWriteToPrivateDirectory() -> Bool {
        let testPath = "/private/jailbreak_test.txt"
        do {
            try "test".write(toFile: testPath, atomically: true, encoding: .utf8)
            try FileManager.default.removeItem(atPath: testPath)
            return true
        } catch {
            return false
        }
    }
    
    private func hasSuspiciousLibraries() -> Bool {
        let suspiciousLibraries = [
            "MobileSubstrate",
            "SubstrateLoader",
            "SSLKillSwitch",
            "Frida"
        ]
        
        for i in 0..<_dyld_image_count() {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName)
                for library in suspiciousLibraries {
                    if name.contains(library) {
                        return true
                    }
                }
            }
        }
        return false
    }
    
    private func isDebugged() -> Bool {
        var info = kinfo_proc()
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        var size = MemoryLayout<kinfo_proc>.stride
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        
        if result != 0 {
            return false
        }
        
        return (info.kp_proc.p_flag & P_TRACED) != 0
    }
    
    private func isReverseEngineered() -> Bool {
        if let _ = getenv("DYLD_INSERT_LIBRARIES") {
            return true
        }
        return false
    }
}

// MARK: - Secure Storage

class SecureStorage {
    static let shared = SecureStorage()
    
    private init() {}
    
    func save(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess,
              let data = result as? Data,
              let value = String(data: data, encoding: .utf8) else {
            return nil
        }
        
        return value
    }
    
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

// MARK: - Encryption

class EncryptionManager {
    static let shared = EncryptionManager()
    
    private init() {}
    
    func encrypt(data: Data, key: Data) -> Data? {
        return crypt(data: data, key: key, operation: CCOperation(kCCEncrypt))
    }
    
    func decrypt(data: Data, key: Data) -> Data? {
        return crypt(data: data, key: key, operation: CCOperation(kCCDecrypt))
    }
    
    private func crypt(data: Data, key: Data, operation: CCOperation) -> Data? {
        let keyLength = kCCKeySizeAES256
        let ivSize = kCCBlockSizeAES128
        
        var keyData = key
        keyData.count = keyLength
        
        var iv = Data(count: ivSize)
        _ = iv.withUnsafeMutableBytes { ivBytes in
            SecRandomCopyBytes(kSecRandomDefault, ivSize, ivBytes.baseAddress!)
        }
        
        let dataLength = data.count
        let cryptLength = dataLength + kCCBlockSizeAES128
        var cryptData = Data(count: cryptLength)
        
        var numBytesEncrypted: size_t = 0
        
        let cryptStatus = cryptData.withUnsafeMutableBytes { cryptBytes in
            data.withUnsafeBytes { dataBytes in
                iv.withUnsafeBytes { ivBytes in
                    keyData.withUnsafeBytes { keyBytes in
                        CCCrypt(
                            operation,
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, keyLength,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress, dataLength,
                            cryptBytes.baseAddress, cryptLength,
                            &numBytesEncrypted
                        )
                    }
                }
            }
        }
        
        guard cryptStatus == kCCSuccess else { return nil }
        
        cryptData.count = numBytesEncrypted
        
        if operation == kCCEncrypt {
            return iv + cryptData
        } else {
            return cryptData
        }
    }
    
    func generateKey() -> Data {
        var keyData = Data(count: kCCKeySizeAES256)
        _ = keyData.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, kCCKeySizeAES256, bytes.baseAddress!)
        }
        return keyData
    }
}

