// MARK: - Trading Manager

class TradingManager {
    static let shared = TradingManager()
    
    private init() {}
    
    func executeTrade(symbol: String, type: Trade.TradeType, quantity: Int, price: Double, completion: @escaping (Result<Trade, Error>) -> Void) {
        guard SecurityManager.shared.performSecurityChecks() else {
            completion(.failure(NSError(domain: "TradingManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Security check failed"])))
            return
        }
        
        BiometricAuthManager.shared.authenticate(reason: "Authenticate to execute trade") { success, error in
            if success {
                APIClient.shared.executeTrade(symbol: symbol, type: type, quantity: quantity, price: price, completion: completion)
            } else {
                completion(.failure(error ?? NSError(domain: "TradingManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Authentication failed"])))
            }
        }
    }
    
    func validateTrade(symbol: String, type: Trade.TradeType, quantity: Int, price: Double, portfolio: Portfolio) -> (valid: Bool, message: String) {
        if quantity <= 0 {
            return (false, "Quantity must be greater than 0")
        }
        
        if price <= 0 {
            return (false, "Price must be greater than 0")
        }
        
        let totalCost = Double(quantity) * price
        
        if type == .buy {
            if totalCost > portfolio.cashBalance {
                return (false, "Insufficient funds")
            }
        } else {
            if let holding = portfolio.holdings.first(where: { $0.symbol == symbol }) {
                if quantity > holding.quantity {
                    return (false, "Insufficient shares")
                }
            } else {
                return (false, "No shares to sell")
            }
        }
        
        return (true, "Trade valid")
    }
}

// MARK: - Portfolio Manager

class PortfolioManager {
    static let shared = PortfolioManager()
    
    private var portfolio: Portfolio?
    private var updateTimer: Timer?
    
    private init() {}
    
    func loadPortfolio(completion: @escaping (Result<Portfolio, Error>) -> Void) {
        APIClient.shared.getPortfolio { result in
            switch result {
            case .success(let portfolio):
                self.portfolio = portfolio
                completion(.success(portfolio))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func startAutoUpdate(interval: TimeInterval = 30) {
        updateTimer?.invalidate()
        updateTimer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            self?.loadPortfolio { _ in }
        }
    }
    
    func stopAutoUpdate() {
        updateTimer?.invalidate()
        updateTimer = nil
    }
    
    func getCurrentPortfolio() -> Portfolio? {
        return portfolio
    }
    
    func calculateTotalValue() -> Double {
        guard let portfolio = portfolio else { return 0 }
        let holdingsValue = portfolio.holdings.reduce(0) { $0 + $1.totalValue }
        return holdingsValue + portfolio.cashBalance
    }
    
    func calculateTotalGainLoss() -> Double {
        guard let portfolio = portfolio else { return 0 }
        return portfolio.holdings.reduce(0) { $0 + $1.gainLoss }
    }
}

