        let totalValue = PortfolioManager.shared.calculateTotalValue()
        let gainLoss = PortfolioManager.shared.calculateTotalGainLoss()
        
        totalValueLabel.text = String(format: "$%.2f", totalValue)
        
        let gainLossText = String(format: "$%.2f", abs(gainLoss))
        gainLossLabel.text = gainLoss >= 0 ? "+\(gainLossText)" : "-\(gainLossText)"
        gainLossLabel.textColor = gainLoss >= 0 ? .systemGreen : .systemRed
        
        cashBalanceLabel.text = String(format: "Cash: $%.2f", portfolio.cashBalance)
        
        tableView.reloadData()
    }
    
    @objc private func refreshTapped() {
        loadPortfolio()
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return portfolio?.holdings.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "HoldingCell", for: indexPath) as! HoldingCell
        
        if let holding = portfolio?.holdings[indexPath.row] {
            cell.configure(with: holding)
        }
        
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 80
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        
        if let holding = portfolio?.holdings[indexPath.row] {
            let tradeVC = TradeViewController(symbol: holding.symbol)
            navigationController?.pushViewController(tradeVC, animated: true)
        }
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

