class TradeViewController: UIViewController {
    
    private let symbol: String
    private var stock: Stock?
    
    private let symbolLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 32, weight: .bold)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let priceLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 24)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let changeLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 18)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let segmentedControl: UISegmentedControl = {
        let control = UISegmentedControl(items: ["Buy", "Sell"])
        control.selectedSegmentIndex = 0
        control.translatesAutoresizingMaskIntoConstraints = false
        return control
    }()
    
    private let quantityTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Quantity"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .numberPad
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let totalLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 20, weight: .semibold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let executeButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Execute Trade", for: .normal)
        button.backgroundColor = .systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let activityIndicator: UIActivityIndicatorView = {
        let indicator = UIActivityIndicatorView(style: .medium)
        indicator.hidesWhenStopped = true
        indicator.translatesAutoresizingMaskIntoConstraints = false
        return indicator
    }()
    
    init(symbol: String) {
        self.symbol = symbol
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        setupUI()
        loadStockQuote()
        
        quantityTextField.addTarget(self, action: #selector(quantityChanged), for: .editingChanged)
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade"
        
        view.addSubview(symbolLabel)
        view.addSubview(priceLabel)
        view.addSubview(changeLabel)
        view.addSubview(segmentedControl)
        view.addSubview(quantityTextField)
        view.addSubview(totalLabel)
        view.addSubview(executeButton)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            symbolLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 24),
            symbolLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            priceLabel.topAnchor.constraint(equalTo: symbolLabel.bottomAnchor, constant: 8),
            priceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            changeLabel.topAnchor.constraint(equalTo: priceLabel.bottomAnchor, constant: 4),
            changeLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            segmentedControl.topAnchor.constraint(equalTo: changeLabel.bottomAnchor, constant: 32),
            segmentedControl.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            segmentedControl.widthAnchor.constraint(equalToConstant: 300),
            
            quantityTextField.topAnchor.constraint(equalTo: segmentedControl.bottomAnchor, constant: 24),
            quantityTextField.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            quantityTextField.widthAnchor.constraint(equalToConstant: 300),
            quantityTextField.heightAnchor.constraint(equalToConstant: 44),
            
            totalLabel.topAnchor.constraint(equalTo: quantityTextField.bottomAnchor, constant: 16),
            totalLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            executeButton.topAnchor.constraint(equalTo: totalLabel.bottomAnchor, constant: 32),
            executeButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            executeButton.widthAnchor.constraint(equalToConstant: 300),
            executeButton.heightAnchor.constraint(equalToConstant: 44),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.topAnchor.constraint(equalTo: executeButton.bottomAnchor, constant: 16)
        ])
        
        executeButton.addTarget(self, action: #selector(executeTapped), for: .touchUpInside)
    }
    
    private func loadStockQuote() {
        APIClient.shared.getStockQuote(symbol: symbol) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let stock):
                    self?.stock = stock
                    self?.updateUI()
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    private func updateUI() {
        guard let stock = stock else { return }
        
        symbolLabel.text = stock.symbol
        priceLabel.text = String(format: "$%.2f", stock.price)
        
        let changeText = String(format: "$%.2f (%.2f%%)", abs(stock.change), abs(stock.changePercent))
        changeLabel.text = stock.change >= 0 ? "+\(changeText)" : "-\(changeText)"
        changeLabel.textColor = stock.change >= 0 ? .systemGreen : .systemRed
        
        updateTotal()
    }
    
    @objc private func quantityChanged() {
        updateTotal()
    }
    
    private func updateTotal() {
        guard let stock = stock,
              let quantityText = quantityTextField.text,
              let quantity = Int(quantityText), quantity > 0 else {
            totalLabel.text = "Total: $0.00"
            return
        }
        
        let total = Double(quantity) * stock.price
        totalLabel.text = String(format: "Total: $%.2f", total)
    }
    
    @objc private func executeTapped() {
        guard let stock = stock,
              let quantityText = quantityTextField.text,
              let quantity = Int(quantityText), quantity > 0 else {
            showAlert(message: "Please enter a valid quantity")
            return
        }
        
        guard let portfolio = PortfolioManager.shared.getCurrentPortfolio() else {
            showAlert(message: "Unable to load portfolio")
            return
        }
        
        let tradeType: Trade.TradeType = segmentedControl.selectedSegmentIndex == 0 ? .buy : .sell
        
        let validation = TradingManager.shared.validateTrade(symbol: symbol, type: tradeType, quantity: quantity, price: stock.price, portfolio: portfolio)
        
        if !validation.valid {
            showAlert(message: validation.message)
            return
        }
        
        let confirmMessage = tradeType == .buy ?
            "Buy \(quantity) shares of \(symbol) at $\(String(format: "%.2f", stock.price))?" :
            "Sell \(quantity) shares of \(symbol) at $\(String(format: "%.2f", stock.price))?"
        
        let alert = UIAlertController(title: "Confirm Trade", message: confirmMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Confirm", style: .default) { [weak self] _ in
            self?.executeTradeWithAuth(type: tradeType, quantity: quantity, price: stock.price)
        })
        present(alert, animated: true)
    }
    
    private func executeTradeWithAuth(type: Trade.TradeType, quantity: Int, price: Double) {
        activityIndicator.startAnimating()
        executeButton.isEnabled = false
        
        TradingManager.shared.executeTrade(symbol: symbol, type: type, quantity: quantity, price: price) { [weak self] result in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                self?.executeButton.isEnabled = true
                
                switch result {
                case .success(let trade):
                    self?.showSuccessAlert(trade: trade)
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    private func showSuccessAlert(trade: Trade) {
        let message = "Trade executed successfully!\nID: \(trade.id)"
        let alert = UIAlertController(title: "Success", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { [weak self] _ in
            self?.navigationController?.popViewController(animated: true)
        })
        present(alert, animated: true)
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class TradeHistoryViewController: UIViewController, UITableViewDelegate, UITableViewDataSource {
    
    private let tableView: UITableView = {
        let table = UITableView()
        table.translatesAutoresizingMaskIntoConstraints = false
        return table
    }()
    
    private var trades: [Trade] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        setupUI()
        loadTradeHistory()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade History"
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .refresh, target: self, action: #selector(refreshTapped))
        
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(TradeCell.self, forCellReuseIdentifier: "TradeCell")
    }
    
    private func loadTradeHistory() {
        APIClient.shared.getTradeHistory { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let trades):
                    self?.trades = trades.sorted { $0.timestamp > $1.timestamp }
                    self?.tableView.reloadData()
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    @objc private func refreshTapped() {
        loadTradeHistory()
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return trades.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TradeCell", for: indexPath) as! TradeCell
        cell.configure(with: trades[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 80
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

